var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"탑 카운터?","JPN":"トップカウンター？","ENG":"Top Counter?","TWN":"TOP制裁者？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다네. 자네의 CRF 측정 등급은 관리국 설립 이래 최고 수준이지.","JPN":"ああ。\\n君のCRF測定ランクは管理局設立以来、最高レベルだ。","ENG":"Yes. Your CRF level is the highest we've seen, ever since the start of the Administration.","TWN":"沒錯，你的CRF測量等級，是管理局有史以來最高的。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"등록에 동의만 한다면 공식적인 경로를 통해 관리국 탑 카운터로 지정될 걸세.","JPN":"登録に同意すれば、公式的な手順で\\n管理局のトップカウンターとして指定されるだろう。","ENG":"If you agree, the Administration will officially designate you as Top Counter.","TWN":"只要你同意加入，就會透過正式的管道指定為最強制裁者！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"지난번에 찾아 온 행정관은 그런 말 안 하던데, 당신 누구야?","JPN":"この前来た行政官はそんなことを言ってなかったが、あんた何者だ？","ENG":"The officer I met last time didn’t mention that. Who are you?","TWN":"上次來找我的行政官沒提到這些，你是誰？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 행정관보다는 높은 직책에 있는 사람이지.","JPN":"その行政官よりは高い役職に就いている人間、と言っておこう。","ENG":"I’m someone who’s in a higher position than the officer you met before.","TWN":"當然是職位比那個行政官更高的人囉！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"탑 카운터로 지정되면 많은 혜택이 있어.","JPN":"トップカウンターに指定されると、その恩恵もたくさんある。","ENG":"Being Top Counter has a lot of benefits.","TWN":"成為最強制裁者有很多好處喔！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"명예나 금전적인 이야기는 차치하고서라도, 외부에 공개되지 않은 관리국의 최신 장비도 마음껏 사용할 수 있지.","JPN":"名誉や金銭的な話はもちろん、外部に公開されていない\\n管理局の最新装備も思う存分使える。","ENG":"Not to mention the money and honor that comes with it, but you can also use the most advanced tech the Administration has, more advanced than anything you could dream of.","TWN":"　"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"강해지고 싶지 않나? 지금보다 훨씬?","JPN":"強くなりたいだろ？　今よりもさらに。","ENG":"Don’t you want to be stronger? Far stronger than ever?","TWN":"你不想變得比現在更強嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"미안하지만 사양하겠어.","JPN":"悪いが遠慮しとくよ。","ENG":"Sorry, but my answer is no.","TWN":"謝謝你的好意，我拒絕。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"좋아. 그럼 여기 사인을…… 음?","JPN":"よし。じゃあ、ここにサインを……うん？","ENG":"Okay, then sign here... huh?","TWN":"很好，那請你在這裡簽……什麼？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"사양한다고 했어.","JPN":"遠慮するって言ってんだ。","ENG":"I said no.","TWN":"我說我拒絕。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"관리국 소속이면 결국 용병이나 다름없잖아. 돈을 받고 일을 하는.","JPN":"管理局所属ってことは、つまり傭兵と変わらないだろ。\\n金をもらって仕事をする……","ENG":"Being in the Administration is not very different from being a mercenary, is it? You work and get paid.","TWN":"隸屬於管理局的意思不就跟傭兵一樣，就是拿錢辦事。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇긴 하지. 세계를 구하는 일에는 예산이 아주 많이 필요하니까.","JPN":"そうだな。世界を救うためには多額の予算が必要だ。","ENG":"You could say that. Saving the world costs a lot of money, you know.","TWN":"話是沒錯，但拯救世界需要很多預算吧？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네는 돈이 싫은가?","JPN":"君はお金が嫌いなのか？","ENG":"You don’t like money?","TWN":"你不喜歡錢嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"돈이 필요 없다는 건 아니야. 무서워서 그렇지.","JPN":"お金が要らないわけじゃない。ただ、怖いだけだ。","ENG":"It’s not that. But I’m scared.","TWN":"不是我不需要錢，而是我怕！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그런 식으로 타협하기 시작하면, 언젠가 진짜 용병이 되어 버릴 것 같아서.","JPN":"そんな風に妥協し始めると、\\nいつか本当の傭兵になっちまいそうでな。","ENG":"I’m scared that I might actually become a mercenary someday, if I start to compromise like this.","TWN":"如果我這次選擇妥協，我怕我總有一天會真的變成傭兵！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이러니저러니 해도 내겐 용병이었던 아버지의 피가 흐르고 있으니까.","JPN":"なんだかんだ俺には傭兵だった父親の血が流れているから。","ENG":"I’m a mercenary’s son, after all.","TWN":"畢竟再怎麼說，我身上流的是傭兵父親的血。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"어리광일지도 모르지만…… 난 의뢰비가 아니라 의무를 통해 사람들을 구하고 싶어.","JPN":"勝手な話かもしれないが……\\n俺は報酬のためではなく、義務として人々を救いたい。","ENG":"You might think I’m being idealistic... but I want to save people as my duty, not for a profit.","TWN":"這麼說好像有點驕傲……但我想要的不是委託費，而是在透過義務救人。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"실제로 그 방면으로 아주 훌륭한 롤 모델도 있고 말이야.","JPN":"実際にその方面でとても立派なお手本がいるしな。","ENG":"I also have a very good role model for that.","TWN":"而在這條路上，我也有看到一個非常好的榜樣。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"난 자네의 의견에 동의하지 않네.","JPN":"私は君の意見に同意はしない。","ENG":"I don’t really agree with you.","TWN":"我不同意你的說法！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아주 비합리적이고 멍청한 의견이라고 생각하지.","JPN":"とても非合理的で愚かな意見だと思う。","ENG":"I think you’re being very stupid and irrational.","TWN":"甚至覺得非常不符合邏輯而且愚蠢。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"뭐야?!","JPN":"なんだと！？","ENG":"What?!","TWN":"你說什麼？！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG"},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"だが……","ENG":"But...","TWN":"不過……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"개인적으로는 자네처럼 멍청한 친구들이 그다지 싫지 않아.","JPN":"個人的には、君のような愚かな人は嫌いじゃない。","ENG":"I don't dislike a stupid person like you.","TWN":"就個人而言，我並不討厭像你這種笨蛋。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"바로 그런 멍청이들이 진정으로 위대한 일을 이루는 걸 종종 보곤 했거든.","JPN":"まさにそんな馬鹿なやつらが本当の偉業を成し遂げるのを、\\nたびたび見てきたんでね。","ENG":"Because I've seen the stupid like you change the world.","TWN":"畢竟我看過不少例子，很多時候就是因為有你們這種笨蛋，才能成就真正偉大的事。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이봐, 당신 대체 무슨 말을 하고 싶은 거야……?","JPN":"おい、あんたはいったい何が言いたいんだ……？","ENG":"So what’s your point?","TWN":"喂，你到底想說什麼……？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네의 의견은 받아들이겠네. 탑 카운터 지정은 없던 일로 하지.","JPN":"君の意見を受け入れよう。トップカウンター指定はなかったことにしよう。","ENG":"I accept your refusal. You won’t be appointed as Top Counter.","TWN":"我接受你的拒絕，最強制裁者就當我沒說過吧！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"한 번 어려운 길을 가기로 정했으니, 마지막까지 꺾이지 않기를 기대하겠네.","JPN":"厳しい道を歩むことに決めたからには、\\n最後までその意志が変わらないことを期待するよ。","ENG":"You chose a difficult path, and I hope you make it till the end.","TWN":"既然你決定選擇難走的路，我期待你可以堅持走完。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어쩌면……. 자네 역시 위대한 일을 이룰지도 모르니까.","JPN":"もしかしたら……君も偉業を成し遂げるかもしれないからね。","ENG":"Maybe... you will also achieve something great.","TWN":"或許……你也能成就偉大的事！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하늘이…… 어째 이상한데.","JPN":"空が……なんだかおかしい。","ENG":"The sky doesn’t look good.","TWN":"天空……好像怪怪的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭔가 커다란 그림자가 다가오는 것 같아……!","JPN":"何か大きな影が近づいてる気がする……！","ENG":"I think I see a giant shadow!","TWN":"好像有個巨大的黑影靠近中……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저도 이런 말 드리고 싶진 않지만……. 솔직히 겁이 좀 나는데요?","JPN":"僕もこんなことは言いたくないですが……正直少し怖いですね。","ENG":"I hate to say this... but I’m a bit scared.","TWN":"雖然我不想說這種話……但老實說我有點害怕。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"어쩌면 돌이킬 수 없는 일이 벌어질지도 모르겠어요.","JPN":"もしかしたら、取り返しのつかないことが起こるかもしれません。","ENG":"Perhaps something irreversible will happen...","TWN":"感覺好像會發生什麼無法挽回的事一樣！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만 샬롯의 방어가 너무 강해. 이대로는……","JPN":"でもシャーロットの守備が硬すぎる。このままじゃ……","ENG":"But Carlota’s defense is too strong. We can’t go on like this...","TWN":"但是夏洛特的防禦太強，這樣下去……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"아무도…… 아무도 지나갈 수 없다!","JPN":"誰も……ここから先へは行かせない！","ENG":"No one... No one shall pass!","TWN":"任何一個人……都別想越過我！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"……어쩔 수 없군.","JPN":"……仕方ないな。","ENG":"I guess I have no choice.","TWN":"……不能這樣下去！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"제이나 크로펠 요원. 지금부터 다른 사람들을 데리고 등대를 파괴하러 가라.","JPN":"ジェイナ・クロペル要員。今からみんなを連れて灯台の破壊に向かえ。","ENG":"Agent Jaina Kropel. Take the others with you and destroy the Lighthouse.","TWN":"婕娜·克洛佩爾幹員，你立刻帶著其他人去破壞燈塔！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"저, 저도 그러고 싶지만…… 저 아이가 계속 가로막아서 지나갈 수가 없어요!","JPN":"わ、私もそうしたいのですが……\\nあの子がずっと立ちはだかっていて進めません！","ENG":"I-I want to... but the girl is blocking the way!","TWN":"我也想那麼做…… 但那個女孩一直擋住去路，我們過不去！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"걱정 마. 저 아가씨는 내가 막을 테니까.","JPN":"心配すんな。あのお嬢ちゃんは俺が止める。","ENG":"Don’t worry. I’ll stop her.","TWN":"放心，我來攔住那個小丫頭！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"불가능해요, 대령님!","JPN":"いけません、大佐！","ENG":"But that’s impossible, Colonel!","TWN":"上校，你攔不住她的！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"직감적으로 느껴져요. 저 아이는 분명 불멸체 코어의 지원을 받던 리플레이서 퀸보다 강해요.","JPN":"直感ですがわかります。\\nあの子は確実に不滅体コアの力を授かったリプレイサー・クイーンよりも強いです。","ENG":"I can feel it. She’s far stronger than the Replacer Queen with the Immortal System Core.","TWN":"我有預感，她絕對比有不滅者核心支撐的克隆·女皇還強！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"아무리 당신이라도 혼자서는…….","JPN":"いくらあなたでも一人では……","ENG":"Even you won’t be able to...","TWN":"你再怎麼厲害，只有一個人也……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"막을 수 있어.","JPN":"止められる。","ENG":"I can.","TWN":"我攔得住她！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"리플레이서 퀸과 싸웠을 때도 재생력에 밀렸을 뿐이지.","JPN":"リプレイサー・クイーンと戦った時も再生力で押されただけさ。","ENG":"When I fought the Replacer Queen, she beat me only because she had the regeneration ability.","TWN":"和克隆·女皇交手時，她只是強在再生力。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"순간 화력은 분명 내 쪽이 앞섰다.","JPN":"瞬間火力は確実に俺のほうが強かった。","ENG":"I definitely had the superior momentary power.","TWN":"以瞬間火力來說，很明顯是我佔優勢。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"그건…… 그렇다고 해도…….","JPN":"それは……そうだとしても………","ENG":"But... Even so...","TWN":"可是……話雖如此……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"할 수 없더라도 해내야 해.","JPN":"できなくても、やるしかない。","ENG":"I have to make it, even if I’m not capable.","TWN":"就算攔不住也必須要攔住！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이런 곳에서 꺾여 버리면 그 남자의 제안을 거절했던 게 너무 쪽팔리잖아?","JPN":"こんなところで折れてしまったら、あの男の提案を断った俺が情けないだろ？","ENG":"If I were to give up here, I wouldn’t have turned down the man’s offer.","TWN":"就這樣認輸的話，那我當初信誓旦旦地拒絕那個男人的提議，不是很丟臉嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"꺄악!","JPN":"きゃっ！","ENG":"Wah!","TWN":"啊！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"대령? 뭐지, 그 엄청난 번개는?","JPN":"大佐？　何だ、あのとんでもない稲妻は？","ENG":"Colonel? What was that giant lightning bolt?","TWN":"上校？那個巨大的閃電是怎麼回事？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"지금부터 춤 상대는 나 하나다. 도둑 기사 아가씨.","JPN":"これからのダンスの相手は俺一人だぜ、泥棒のお嬢ちゃん。","ENG":"From now, you’ll dance only with me, thieving knight girl.","TWN":"現在開始，你的目標只有我一個人，小偷騎士！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이번 싸움으로 워치가 타 버리더라도 전력…….","JPN":"この戦いでウォッチが燃え尽きてしまうとしても、全力で……","ENG":"I don’t care if my Watch burns down, I’ll do my best...","TWN":"這次就算會燒毀能量環，我也會全力……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"아니, 한계를 넘어선 번개를 보여 주지.","JPN":"いや、限界を超えた電撃を見せてやる。","ENG":"Nah, I will go beyond my limitations.","TWN":"不，是超出全力地使出閃電！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이것이, 비공식 탑 카운터의 힘이다!","JPN":"これが、非公認トップカウンターの力だ！","ENG":"I'll show you what the Administration's unofficial Top Counter can do!","TWN":"這就是非官方最強制裁者的厲害！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};